"""Ключи локализации project_extract.* для вкладки извлечения (схема провайдеров — только коды)."""def provider_prefix(provider_code: str) -> str:    return f"project_extract.provider.{provider_code}"def field_label(provider_code: str, field_key: str) -> str:    return f"{provider_prefix(provider_code)}.field.{field_key}.label"def field_description(provider_code: str, field_key: str) -> str:    return f"{provider_prefix(provider_code)}.field.{field_key}.description"def field_option(provider_code: str, field_key: str, option_code: str) -> str:    return f"{provider_prefix(provider_code)}.field.{field_key}.option.{option_code}"def provider_title_key(provider_code: str) -> str:    return f"{provider_prefix(provider_code)}.title"def provider_description_key(provider_code: str) -> str:    return f"{provider_prefix(provider_code)}.description"